DO $$
DECLARE
  shakally_id uuid;
  odalis_id uuid;
  lesley_id uuid;
  evelis_id uuid;
BEGIN
  -- Look up profile IDs by email (adjust emails as needed)
  SELECT id INTO shakally_id FROM profiles WHERE email ILIKE '%shakally%' OR email ILIKE '%monzer%' OR role = 'admin' LIMIT 1;
  SELECT id INTO odalis_id FROM profiles WHERE email ILIKE '%odalis%' LIMIT 1;
  SELECT id INTO lesley_id FROM profiles WHERE email ILIKE '%lesley%' LIMIT 1;
  SELECT id INTO evelis_id FROM profiles WHERE email ILIKE '%evelis%' LIMIT 1;

  -- Verify we found all profiles
  IF shakally_id IS NULL THEN RAISE EXCEPTION 'Could not find Shakally profile. Create auth users first.'; END IF;
  IF odalis_id IS NULL THEN RAISE EXCEPTION 'Could not find Odalis profile. Create auth users first.'; END IF;
  IF lesley_id IS NULL THEN RAISE EXCEPTION 'Could not find Lesley profile. Create auth users first.'; END IF;
  IF evelis_id IS NULL THEN RAISE EXCEPTION 'Could not find Evelis profile. Create auth users first.'; END IF;

  RAISE NOTICE 'Found all profiles: Shakally=%, Odalis=%, Lesley=%, Evelis=%', shakally_id, odalis_id, lesley_id, evelis_id;

